{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var seed = GetInt(parameters, "seed", context.Seed);
var noiseType = GetChoice(parameters, "noiseType", "filmGrain");
var strength = GetFloat(parameters, "intensity", 0.3f);
var scale = GetFloat(parameters, "scale", 1f);
var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);
var period = Math.Max(1, (int)MathF.Round(scale * 20f));

result.ParallelForEachPixel((x, y) =>
{
    var (r, g, b, a) = src.GetPixel(x, y);
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    switch (noiseType)
    {
        case "colorNoise":
        {
            var nr = GraphNodeBase.TileableFractalNoise(u * scale * 8f, v * scale * 8f, period, 1, 0.5f, 2f, seed);
            var ng = GraphNodeBase.TileableFractalNoise(u * scale * 8f + 100f, v * scale * 8f + 100f, period, 1, 0.5f, 2f, seed + 50);
            var nb = GraphNodeBase.TileableFractalNoise(u * scale * 8f + 200f, v * scale * 8f + 200f, period, 1, 0.5f, 2f, seed + 100);
            r = Math.Clamp(r + (nr - 0.5f) * strength, 0f, 1f);
            g = Math.Clamp(g + (ng - 0.5f) * strength, 0f, 1f);
            b = Math.Clamp(b + (nb - 0.5f) * strength, 0f, 1f);
            break;
        }
        case "dustScratches":
        {
            var scratch = GraphNodeBase.TileableFractalNoise(u * scale * 2f, v * scale * 20f, period, 1, 0.5f, 2f, seed + 200);
            if (scratch > 0.98f)
            {
                var s = (scratch - 0.98f) / 0.02f * strength;
                r = Math.Clamp(r - s * 0.5f, 0f, 1f);
                g = Math.Clamp(g - s * 0.5f, 0f, 1f);
                b = Math.Clamp(b - s * 0.5f, 0f, 1f);
            }
            // Dust specks
            var dust = GraphNodeBase.TileableFractalNoise(u * scale * 12f + 50f, v * scale * 12f + 50f, Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 300);
            if (dust > 0.995f)
            {
                var d = (dust - 0.995f) / 0.005f * strength;
                r = Math.Clamp(r + d * 0.3f, 0f, 1f);
                g = Math.Clamp(g + d * 0.3f, 0f, 1f);
                b = Math.Clamp(b + d * 0.3f, 0f, 1f);
            }
            break;
        }
        case "snow":
        {
            var snow = GraphNodeBase.TileableFractalNoise(u * scale * 20f, v * scale * 20f, Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 400);
            if (snow > 1f - strength * 0.5f)
            {
                var s = (snow - (1f - strength * 0.5f)) / (strength * 0.5f);
                r = Math.Clamp(r + s * 0.8f, 0f, 1f);
                g = Math.Clamp(g + s * 0.8f, 0f, 1f);
                b = Math.Clamp(b + s * 0.8f, 0f, 1f);
            }
            break;
        }
        case "pixelJitter":
        {
            var jitter = strength * 4f;
            var jx = (int)(MathF.Round(x / Math.Max(1f, jitter)) * Math.Max(1f, jitter));
            var jy = (int)(MathF.Round(y / Math.Max(1f, jitter)) * Math.Max(1f, jitter));
            (r, g, b, a) = src.GetPixelWrapped(jx, jy);
            break;
        }
        default: // filmGrain
        {
            var grain = GraphNodeBase.TileableFractalNoise(u * scale * 10f, v * scale * 10f, Math.Max(1, period / 2), 2, 0.5f, 2f, seed);
            var offset = (grain - 0.5f) * strength;
            r = Math.Clamp(r + offset, 0f, 1f);
            g = Math.Clamp(g + offset * 0.9f, 0f, 1f);
            b = Math.Clamp(b + offset * 0.8f, 0f, 1f);
            break;
        }
    }

    result.SetPixel(x, y, r, g, b, preserveAlpha ? a : 1f);
});

return result;
}
